<template>
  <div
    class="ct-container-pets"
    ref="ct-container-pets"
    :style="{
      left: `${left}px`,
      top: `${top}px`,
      transform: `scale(${scale})`,
      visibility: `${visible ? 'visible' : 'hidden'}`
    }"
  >
    <div class="ct-pets-app flex">
      <div
        class="pets-app"
        :class="{
          active: true,
          petInventory: mode === 2,
          info: mode === 1,
          menuPet: mode === 0,
          statsPet: mode === 3,
        }"
      >
        <div
          class="ct-body-pets"
          ref="ct-body-pets"
          :style="{
            marginLeft: '-50%',
          }"
          v-if="mode === 0 || mode === 1"
        >
          <div class="body-pets">
            <div
              class="ct-menu-pets"
              v-for="(item, index) in menus"
              :key="index"
            >
              <div
                class="menu-pets"
                @mouseover="item.hover = true"
                @mouseleave="item.hover = false"
                @click="() => onClickMenu(item)"
              >
                <div class="ct-icon-menu-pets">
                  <div class="icon-menu-pets">
                    <svgComponentVue v-if="!item.isImage" :icon="item.icon" :hover="item.hover" />
                    <div v-if="item.isImage" class="pet-image" :style="'background-image: url(\'nui://cdev_pets/html/pets/inventory/' + item.icon + '.webp\')'"></div>
                  </div>
                </div>
                <div
                  class="ct-placeholder-pets-name"
                  v-if="item.hover && mode === 0"
                >
                  <div class="placeholder-pets-name">
                    <p class="text-placeholder-pets-name">{{ item.name }}</p>
                  </div>
                </div>
                <div class="ct-keybind-info" v-if="mode === 1">
                  <div class="keybind-info">
                    <p class="text-keybind-info">{{ item.keyBind }}</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
  <div
    class="ct-inventory-container"
    v-if="mode === 2"
    ref="inventory-container"
    @mousemove="onMouseMove"
  >
    <div class="inventory-layout">
      <div class="ct-inventory-pets">
    <div class="inventory-pets">
      <div class="ct-header-inventory-pets">
        <div class="header-inventory-pets">
          <div
            class="ct-menu-inventory-pets"
            v-for="(item, index) in inventoryMenu"
            :key="index"
          >
            <div
              class="menu-inventory-pets"
              v-bind:class="{ selected: item.selected }"
              @mouseover="item.hover = true"
              @mouseleave="item.hover = false"
              @click="() => onClickInventoryMenu(item)"
            >
              <div class="ct-info-menu-hover" v-if="item.hover">
                <div class="info-menu-hover">
                  <div class="ct-text-info-menu-hover">
                    <p class="text-info-menu-hover">{{ locale(item.title) }}</p>
                  </div>
                </div>
              </div>
              <div class="icon-menu-inventory-pets">
                <svgComponentVue :icon="item.icon" :hover="false" />
              </div>
            </div>
          </div>
        </div>
      </div>
      <div class="ct-body-inventory-pets">
        <div class="body-inventory-pets">
          <div
            class="ct-box-item-inventory-pets"
            v-for="index in maxInventorySlot"
            :key="index"
            :data-slot="index"
          >
            <div
              class="box-item-inventory-pets"
              @mouseenter="onMouseEnter($event, index)"
              @mouseleave="onMouseLeave(index)"
              @mousedown="onDragStart($event, index)"
              tabindex="0"
            >
              <div
                v-if="inventoryItemsMenu[index]"
                class="ct-icon-item-inventory-pets"
                :class="{
                  'filter-highlight': getActiveInventoryMenu()?.category === undefined || 
                    getSpec(inventoryItemsMenu[index])?.category === getActiveInventoryMenu()?.category
                }"
              >
                    <div v-if="inventoryItemsMenu[index].clothingData" class="inventory-clothing-indicator">
                      <div class="clothing-indicator-wrapper">
                      <svg v-if="inventoryItemsMenu[index].clothingData.slot === 'collar'" class="clothing-indicator-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M12 4C8.13401 4 5 4.89543 5 6C5 7.10457 8.13401 8 12 8C15.866 8 19 7.10457 19 6C19 4.89543 15.866 4 12 4Z" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M5 6V12C5 13.1046 8.13401 14 12 14C15.866 14 19 13.1046 19 12V6" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M14.5 10L16 18" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M9.5 10L8 18" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <circle cx="12" cy="18" r="2" stroke="white" stroke-width="1.5"/>
                      </svg>
                      
                      <svg v-if="inventoryItemsMenu[index].clothingData.slot === 'outfit'" class="clothing-indicator-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M5 5L9 3V8L5 10V5Z" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M19 5L15 3V8L19 10V5Z" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M9 3H15" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M5 10V20H19V10" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M9 15H15" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                      </svg>
                      
                      <svg v-if="inventoryItemsMenu[index].clothingData.slot === 'boots'" class="clothing-indicator-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M6 12H9L10 18H4L6 12Z" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M18 12H15L14 18H20L18 12Z" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M9 12L8 7C8 6 8.5 5 10 5C11.5 5 12 6 12 7V12" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M15 12L16 7C16 6 15.5 5 14 5C12.5 5 12 6 12 7V12" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                      </svg>
                      
                      <svg v-if="inventoryItemsMenu[index].clothingData.slot === 'accessory'" class="clothing-indicator-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <circle cx="12" cy="12" r="3" stroke="white" stroke-width="1.5"/>
                        <path d="M4 12H9" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M15 12H20" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M12 4L12 9" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M12 15L12 20" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M6.34315 6.34315L9.17157 9.17157" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M14.8284 14.8284L17.6569 17.6568" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                      </svg>
                      
                      <svg v-if="inventoryItemsMenu[index].clothingData.slot === 'undershirt'" class="clothing-indicator-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M6 4H18" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M6 4L7 12V20H17V12L18 4" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M9 4V8" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M15 4V8" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                      </svg>
                      
                      <svg v-if="inventoryItemsMenu[index].clothingData.slot === 'vest'" class="clothing-indicator-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M8 3H16" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M8 3L6 6V20H18V6L16 3" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M6 10H18" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M9 10V15" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M15 10V15" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                      </svg>
                      </div>
                    </div>
                <img
                  :src="getIcon(inventoryItemsMenu[index]?.item)"
                  draggable="false"
                  @error="onPetImageError"
                />
                <div class="item-quantity" v-if="inventoryItemsMenu[index].quantity > 1">
                  {{ inventoryItemsMenu[index].quantity }}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
        </div>
      </div>
      
      <div class="ct-pet-clothing-container">
        <div class="pet-clothing-header">
          <h3>{{ locale("pet_outfit") }}</h3>
        </div>
        
        <div class="pet-clothing-slots">
          <div 
            v-for="(slot, index) in clothingSlots" 
            :key="index"
            class="ct-clothing-slot-container"
            :data-clothing-type="slot.type"
            :data-slot-index="'clothing-' + index"
          >
            <!-- Hide permanent label and show only on hover -->
            <div class="clothing-slot-hover-label">{{ locale(slot.label) }}</div>
            <div 
              class="clothing-slot" 
              @mouseenter="onMouseEnterClothing($event, index)"
              @mouseleave="onMouseLeaveClothing(index)"
              @mousedown="onDragStartClothing($event, index)"
              :title="locale('right_click_clothing_tip')"
            >
              <div class="clothing-slot-icon" :class="{'empty': !slot.item}">
                <template v-if="!slot.item">
                  <div class="clothing-type-indicator">
                    <div class="icon-container">
                      <svg v-if="slot.type === 'collar'" class="clothing-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M12 4C8.13401 4 5 4.89543 5 6C5 7.10457 8.13401 8 12 8C15.866 8 19 7.10457 19 6C19 4.89543 15.866 4 12 4Z" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M5 6V12C5 13.1046 8.13401 14 12 14C15.866 14 19 13.1046 19 12V6" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M14.5 10L16 18" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M9.5 10L8 18" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <circle cx="12" cy="18" r="2" stroke="white" stroke-width="1.5"/>
                      </svg>
                      
                      <svg v-if="slot.type === 'outfit'" class="clothing-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M5 5L9 3V8L5 10V5Z" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M19 5L15 3V8L19 10V5Z" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M9 3H15" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M5 10V20H19V10" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M9 15H15" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                      </svg>
                      
                      <svg v-if="slot.type === 'boots'" class="clothing-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M6 12H9L10 18H4L6 12Z" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M18 12H15L14 18H20L18 12Z" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M9 12L8 7C8 6 8.5 5 10 5C11.5 5 12 6 12 7V12" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M15 12L16 7C16 6 15.5 5 14 5C12.5 5 12 6 12 7V12" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                      </svg>
                      
                      <svg v-if="slot.type === 'accessory'" class="clothing-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <circle cx="12" cy="12" r="3" stroke="white" stroke-width="1.5"/>
                        <path d="M4 12H9" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M15 12H20" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M12 4L12 9" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M12 15L12 20" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M6.34315 6.34315L9.17157 9.17157" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M14.8284 14.8284L17.6569 17.6568" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                      </svg>
                      
                      <svg v-if="slot.type === 'undershirt'" class="clothing-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M6 4H18" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M6 4L7 12V20H17V12L18 4" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M9 4V8" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M15 4V8" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                      </svg>
                      
                      <svg v-if="slot.type === 'vest'" class="clothing-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M8 3H16" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M8 3L6 6V20H18V6L16 3" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <path d="M6 10H18" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M9 10V15" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M15 10V15" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                      </svg>

                       <svg
                       v-if="slot.type === 'toy'" class="clothing-icon" 
    width="120"
    height="120"
    viewBox="0 0 120 120"
    xmlns="http://www.w3.org/2000/svg"
    fill="none"
  >
    <!-- Ears -->
    <circle cx="30" cy="30" r="15" fill="transparent" stroke="#fff" stroke-width="4" />
    <circle cx="90" cy="30" r="15" fill="transparent" stroke="#fff" stroke-width="4" />

    <!-- Head -->
    <circle cx="60" cy="60" r="30" fill="transparent" stroke="#fff" stroke-width="4" />

    <!-- Eyes -->
    <circle cx="50" cy="55" r="3" fill="transparent" />
    <circle cx="70" cy="55" r="3" fill="transparent" />

    <!-- Nose -->
    <circle cx="60" cy="65" r="2" fill="transparent" />
  </svg>
  
                      <svg v-if="slot.type === 'attach1'" class="clothing-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M12 2L15.09 8.26L22 9L17 14L18.18 21L12 17.77L5.82 21L7 14L2 9L8.91 8.26L12 2Z" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <circle cx="12" cy="12" r="3" stroke="white" stroke-width="1.5"/>
                        <path d="M8 8L16 16" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M16 8L8 16" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                      </svg>
                      
                      <svg v-if="slot.type === 'attach2'" class="clothing-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M12 3L13.09 6.26L17 7L15 11L16.18 15L12 13.77L7.82 15L9 11L7 7L10.91 6.26L12 3Z" stroke="white" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                        <rect x="8" y="8" width="8" height="8" rx="2" stroke="white" stroke-width="1.5"/>
                        <path d="M12 10V14" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                        <path d="M10 12H14" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
                      </svg>
                    </div>
                  </div>
                </template>
                <img 
                  v-else
                  :src="getIcon(slot?.item?.item)" 
                  class="clothing-slot-item"
                  draggable="false"
                  @error="onPetImageError"
                />
              </div>
            </div>
          </div>
        </div>
      </div>
      
      <div
        class="ct-placeholder-inventory-pets"
        v-if="placeHolderItem"
        ref="inventory-popup"
        :style="{
          left: placeHolderX + 'px',
          top: placeHolderY + 'px',
        }"
      >
        <div class="placeholder-inventory-pets">
          <div class="popup-header">
            <div class="popup-icon">
              <img :src="getIcon(placeHolderItem?.item)" @error="onPetImageError" />
            </div>
            <div class="popup-title">
              <h3>{{ getSpec(placeHolderItem)?.label }}</h3>
          </div>
            </div>
          
          <div class="popup-description">
            <p>{{ getSpec(placeHolderItem)?.description }}</p>
          </div>
          
          <div class="popup-actions">
            <div
              class="popup-action-button use-button"
              v-if="getSpec(placeHolderItem)?.usable && !placeHolderClothingItem && !placeHolderItem?.clothingData"
              @click="useItem(placeHolderItem)"
            >
              <div class="action-icon">
                  <svg
                    width="14"
                    height="26"
                    viewBox="0 0 14 26"
                    fill="none"
                    xmlns="http://www.w3.org/2000/svg"
                  >
                    <path
                      d="M7.46467 5.7448C7.44728 5.72516 7.43225 5.70571 7.41174 5.68713C7.18456 5.48314 7.17845 5.54336 7.42714 5.31412C7.61137 5.14504 7.83494 5.01274 8.0375 4.86648C8.57343 4.47913 8.92617 3.96035 9.16465 3.34531C9.69969 1.96436 8.1231 1.01029 7.33194 0.193006C6.76036 -0.39834 5.8604 0.50361 6.43142 1.09371C6.87258 1.55039 7.4408 1.92066 7.82478 2.42834C8.25478 2.99668 7.59953 3.62375 7.15058 3.94015C6.45649 4.42919 5.85648 5.0787 5.99513 5.77522C2.88011 6.06625 0 7.77352 0 10.7832V19.2317C0 22.9638 3.0361 26 6.76846 26C10.5006 26 13.5371 22.9638 13.5371 19.2317V10.7826C13.5372 7.49677 10.4801 5.90546 7.46467 5.7448ZM1.27428 10.7826C1.27428 8.54853 3.69939 7.25499 6.21116 7.04015V14.8322C3.9199 14.7169 2.05964 14.1949 1.27428 13.9401V10.7826ZM12.2631 19.231C12.2631 22.2613 9.79814 24.7257 6.76865 24.7257C3.73929 24.7257 1.27428 22.2613 1.27428 19.231V15.2795C2.41202 15.6234 4.55364 16.145 7.08499 16.145C8.70616 16.145 10.4863 15.9281 12.2631 15.3167L12.2631 19.231ZM12.2631 13.9615C10.6518 14.5777 9.00635 14.8185 7.48525 14.8513V7.02132C9.94209 7.16864 12.2631 8.34703 12.2631 10.7831V13.9615ZM11.8321 13.4792C11.8321 13.4792 8.92131 14.2942 7.93133 14.1195V7.65674C10.5661 8.15177 12.2617 8.94854 11.8321 13.4792Z"
                    fill="#4BB543"
                    />
                  </svg>
                </div>
              <div class="action-text">
                    {{ locale("use_item") }}
                </div>
              </div>
            
            <!-- Equip clothing action when hovering over clothing item in inventory -->
            <div
              class="popup-action-button equip-button"
              v-if="placeHolderItem && (placeHolderItem.clothingData || placeHolderItem.attachData) && !placeHolderClothingItem"
              @click="quickEquipItem(placeHolderItem)"
            >
              <div class="action-icon">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M16 4L20 8M20 8L16 12M20 8H8M11.9 16H5C4.44772 16 4 15.5523 4 15V9" stroke="#4BB543" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
                </svg>
                </div>
              <div class="action-text">
                {{ locale("equip_item") }} <span class="shortcut-hint">M2</span>
              </div>
            </div>
            
            <!-- Unequip clothing action when hovering over equipped item -->
            <div
              class="popup-action-button unequip-button"
              v-if="placeHolderClothingItem"
              @click="quickUnequipItem(placeHolderClothingItem.slotIndex)"
            >
              <div class="action-icon">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M8 4L4 8M4 8L8 12M4 8H16M12.1 16H19C19.5523 16 20 15.5523 20 15V9" stroke="#FFA500" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
                </svg>
                </div>
              <div class="action-text">
                {{ locale("unequip_item") }} <span class="shortcut-hint">M2</span>
            </div>
          </div>
          
            <div
              class="popup-action-button delete-button"
              v-if="getSpec(placeHolderItem)?.canbeRemoved && !placeHolderClothingItem"
              @click="deleteItem(placeHolderItem)"
            >
              <div class="action-icon">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M3 6H5H21" stroke="#DC3545" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
                  <path d="M8 6V4C8 3.46957 8.21071 2.96086 8.58579 2.58579C8.96086 2.21071 9.46957 2 10 2H14C14.5304 2 15.0391 2.21071 15.4142 2.58579C15.7893 2.96086 16 3.46957 16 4V6M19 6V20C19 20.5304 18.7893 21.0391 18.4142 21.4142C18.0391 21.7893 17.5304 22 17 22H7C6.46957 22 5.96086 21.7893 5.58579 21.4142C5.21071 21.0391 5 20.5304 5 20V6H19Z" stroke="#DC3545" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
                </svg>
                </div>
              <div class="action-text">
                {{ locale("del_item") }}
              </div>
            </div>
          
            <div
              class="popup-action-button split-button"
              v-if="placeHolderItem && placeHolderItem.quantity > 1 && !placeHolderClothingItem"
              @click="initiateItemSplit(placeHolderItem)"
            >
              <div class="action-icon">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M17 21L12 17L7 21V4C7 3.73478 7.10536 3.48043 7.29289 3.29289C7.48043 3.10536 7.73478 3 8 3H16C16.2652 3 16.5196 3.10536 16.7071 3.29289C16.8946 3.48043 17 3.73478 17 4V21Z" stroke="#007BFF" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
                </svg>
                </div>
              <div class="action-text">
                <span class="shortcut-hint">SHIFT</span> {{ locale("split_item") }}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
  <div class="ct-stats-pets" v-if="mode === 3">
    <div class="stats-pets">
      <div class="ct-header-stats-pets">
        <div class="header-stats-pets">
          <p class="text-header-stats-pets">{{ locale("pet_stats") }}</p>
        </div>
      </div>
      <div class="ct-body-stats-pets">
        <div class="body-stats-pets">
          <div
            class="ct-bars-body-stats-pets"
            v-for="(item, index) in statsPet"
            :key="index"
          >
            <div class="bars-body-stats-pets">
              <div class="ct-top-bars-body-stats-pets">
                <div class="top-bars-body-stats-pets">
                  <p class="text-top-bars-body-stats-pets">
                    {{ locale(item.title) }} {{ petProgress[item.field] }}% 
                  </p>
                </div>
              </div>
              <div class="ct-bottom-bars-body-stats-pets">
                <div class="bottom-bars-body-stats-pets">
                  <progressBarPet
                    :color="item.color"
                    :maxBar="item.maxBar"
                    :progress="petProgress[item.field]"
                  />
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script lang="ts">
import { defineComponent } from "vue";
import NuiComponentMixin from "@/mixins/NuiComponentMixin";
import { PetsMenu } from "@/fakebackend/petsMenuFake";
import { IPetsMenu } from "@/interfaces/IPetsMenu";
import svgComponentVue from "@/utils/svgComponent.vue";
import progressBarPet from "@/utils/progressBarPet.vue";
import {
  InventoryPetsMenu,
  InventoryPetsMenuItems,
  InventoryItemSpecs,
} from "@/fakebackend/petsInventoryMenu";
import {
  IInventoryPetsMenu,
  IInventoryPetsMenuItem,
  IInventoryItemSpec,
  IClothingData
} from "@/interfaces/IInventoryPetsMenu";
import { DefaultPetBars } from "@/interfaces/IPetBars";
import { petStatsFake } from "@/fakebackend/petStatsFake";
import { IPetBars } from "@/interfaces/IPetBars";
import { ECategoryInventoryPets } from "@/enums/ECategoryInventoryPet";

export interface IClothingSlot {
  type: string;
  label: string;
  item: IInventoryPetsMenuItem | null;
  attach?: boolean; 
}

export default defineComponent({
  name: "cDevPets",
  components: { svgComponentVue, progressBarPet },
  mixins: [NuiComponentMixin],
  data() {
    return {
      placeHolderX: 0,
      placeHolderY: 0,
      placeHolderItem: null as IInventoryPetsMenuItem | null,
      placeHolderClothingItem: null as { item: IInventoryPetsMenuItem, slotIndex: number } | null,
      menus: PetsMenu,
      petProgress: petStatsFake,
      statsPet: DefaultPetBars,
      inventoryMenu: InventoryPetsMenu,
      inventoryItemsMenu: InventoryPetsMenuItems,
      inventoryItemSpecs: InventoryItemSpecs,
      maxInventorySlot: 25,
      left: 900,
      top: 400,
      mode: -1,
      scale: 1,
      draggingItem: null as HTMLElement | null,
      draggingFromClothing: false,
      draggingClothingIndex: -1,
      isShiftDragging: false,
      splitSourceSlot: null as number | null,
      splitAmount: 1,
      currentPetType: 'default',
      clothingSlots: [
        { type: 'collar', label: 'pet_collar', item: null },
        { type: 'outfit', label: 'pet_outfit', item: null },
        { type: 'boots', label: 'pet_boots', item: null },
        { type: 'accessory', label: 'pet_accessory', item: null },
        { type: 'undershirt', label: 'pet_undershirt', item: null },
        { type: 'vest', label: 'pet_vest', item: null },
        { type: 'toy', label: 'pet_toy', item: null, attach: true }
      ] as IClothingSlot[],
      processingUnequip: new Set<number>(),
      lastUnequipTime: {} as { [slotIndex: number]: number },
      processingEquip: new Set<string>(),
      lastEquipTime: {} as { [key: string]: number },
    };
  },
  props: {
    visible: Boolean,
    name: {
      type: String,
    },
    locale: {
      type: Function,
      required: true,
    },
  },
  methods: {
    getActiveInventoryMenu() {
      return this.inventoryMenu.find((item) => item.selected);
    },
    onClickInventoryMenu(menu: IInventoryPetsMenu) {
      for (const item of this.inventoryMenu) {
        item.selected = false;
      }

      menu.selected = true;
    },
    onMouseLeave(indexItem: number) {
      if (this.inventoryItemsMenu[indexItem]) {
        this.placeHolderItem = null;
      }
      return;
    },
    onMouseEnter(e: MouseEvent, indexItem: number) {
      const item = this.inventoryItemsMenu[indexItem];
      if (item) {
        if ([undefined, this.getSpec(item)?.category].includes(this.getActiveInventoryMenu()?.category)) {
          item.slot = indexItem;
          this.placeHolderItem = item;
        }
      }

      return;
    },
    onDragStart(e: MouseEvent, indexItem: number) {
      if (e.button !== 0) {
        if (e.button === 2) {
          const item = this.inventoryItemsMenu[indexItem];
          const spec = this.getSpec(item);
          
          if (item.clothingData) {
            const targetType = item.clothingData.slot;
            const targetSlotIndex = this.clothingSlots.findIndex(slot => slot.type === targetType);
            
            if (targetSlotIndex !== -1) {
              const equipKey = `${indexItem}-${targetSlotIndex}`;
              const currentTime = Date.now();
              const QUICK_DEBOUNCE = 200; 
              
              if (this.lastEquipTime[equipKey] && 
                  (currentTime - this.lastEquipTime[equipKey]) < QUICK_DEBOUNCE) {
                return;
              }
              
              this.equipItemToClothingSlot(item, indexItem, targetSlotIndex);
              this.showFloatingMessage(this.locale('item_equipped'), indexItem);
              return;
            }
          }
          else if (item.attachData) {
            const targetType = item.attachData.slot;
            const targetSlotIndex = this.clothingSlots.findIndex(slot => slot.type === targetType && slot.attach);
            
            if (targetSlotIndex !== -1) {
              const equipKey = `${indexItem}-${targetSlotIndex}`;
              const currentTime = Date.now();
              const QUICK_DEBOUNCE = 200; 
              
              if (this.lastEquipTime[equipKey] && 
                  (currentTime - this.lastEquipTime[equipKey]) < QUICK_DEBOUNCE) {
                return;
              }
              
              this.equipItemToClothingSlot(item, indexItem, targetSlotIndex);
              this.showFloatingMessage(this.locale('item_equipped'), indexItem);
              return;
            }
          }
          else if (spec.usable && !!spec.onUse) {
            this.postNUI("inv-use-item", {
              event: spec.onUse.event,
              net: spec.onUse.net,
              close: spec.onUse.close,
              preventRestoreState: spec.onUse.preventRestoreState,
              item: item.item,
              isPremiumPackage: spec.isPremiumPackage,
              data: {
                ...(spec.onUse.data ? spec.onUse.data : {}),
                metadata: item.metadata,
              },
            });
          }
        }
        return;
      }
      
      const target = (e.target as HTMLElement)?.closest(".ct-box-item-inventory-pets") as HTMLElement;
      if (!target) return;

      if (this.draggingItem) {
        this.draggingItem.remove();
        this.draggingItem = null;
      }

      if (!target.dataset.slot || !this.inventoryItemsMenu[+target.dataset.slot]) return;

      const boxElement = target.querySelector('.box-item-inventory-pets') as HTMLElement;
      if (!boxElement) return;
      
      const clone = boxElement.cloneNode(true) as HTMLElement;
      clone.style.position = "absolute";
      clone.style.pointerEvents = "none";
      clone.style.zIndex = "1000";
      
      const rect = boxElement.getBoundingClientRect();
      clone.style.width = rect.width + "px";
      clone.style.height = rect.height + "px";
      clone.dataset.slot = target.dataset.slot;

      document.body.appendChild(clone);
      this.draggingItem = clone;
      
      this.draggingItem.style.left = (e.clientX - rect.width / 2) + "px";
      this.draggingItem.style.top = (e.clientY - rect.height / 2) + "px";
      this.draggingItem.style.visibility = "visible";
      
      if (e.shiftKey && this.inventoryItemsMenu[+target.dataset.slot].quantity > 1) {
        this.isShiftDragging = true;
        this.splitSourceSlot = +target.dataset.slot;
        this.splitAmount = 1;
      } else {
        this.isShiftDragging = false;
        this.splitSourceSlot = null;
      }
      
      this.addClothingSlotListeners(+target.dataset.slot);
    },
    onMouseMove(e: MouseEvent) {
      const container = this.$refs["inventory-container"] as HTMLElement;
      if (!container) return;
      
      const popup = this.$refs["inventory-popup"] as HTMLElement;
      if (popup) {
        const containerRect = container.getBoundingClientRect();
        this.placeHolderX = e.clientX - containerRect.left + 15;
        this.placeHolderY = e.clientY - containerRect.top + 15;
      }

      if (!this.draggingItem) {
        if (document.querySelector('.valid-target, .invalid-target, .valid-inventory-target')) {
          this.removeClothingSlotListeners();
          this.removeInventorySlotListeners();
        }
        return;
      }

      requestAnimationFrame(() => {
        if (!this.draggingItem) return;
        this.draggingItem.style.left = (e.clientX - this.draggingItem.offsetWidth / 2) + "px";
        this.draggingItem.style.top = (e.clientY - this.draggingItem.offsetHeight / 2) + "px";
        this.draggingItem.style.visibility = "visible";
      });
      
      if (!this.draggingFromClothing && this.draggingItem.dataset.slot 
          && !document.querySelector('.valid-target')) {
        const itemSlot = parseInt(this.draggingItem.dataset.slot || "0");
        const item = this.inventoryItemsMenu[itemSlot];
        
        if (item?.clothingData) {
          const clothingSlots = document.querySelectorAll('.clothing-slot');
          const slotType = item.clothingData.slot;
          
          clothingSlots.forEach(slotEl => {
            const container = slotEl.closest('.ct-clothing-slot-container') as HTMLElement | null;
            if (!container) return;
            
            if (((container as HTMLElement).dataset.clothingType || "") === slotType) {
              slotEl.classList.add('valid-target');
            } else {
              slotEl.classList.add('invalid-target');
            }
          });
        } else if (item?.attachData) {
          const clothingSlots = document.querySelectorAll('.clothing-slot');
          const slotType = item.attachData.slot;
          
          clothingSlots.forEach(slotEl => {
            const container = slotEl.closest('.ct-clothing-slot-container') as HTMLElement | null;
            if (!container) return;
            
            if (((container as HTMLElement).dataset.clothingType || "") === slotType) {
              slotEl.classList.add('valid-target');
            } else {
              slotEl.classList.add('invalid-target');
            }
          });
        }
      }
      
      if (this.draggingFromClothing && !document.querySelector('.valid-inventory-target')) {
        document.querySelectorAll('.ct-box-item-inventory-pets').forEach(slotEl => {
          const slotIndex = (slotEl as HTMLElement).getAttribute('data-slot') || "";
          if (!slotIndex || this.inventoryItemsMenu[slotIndex]) return;
          slotEl.classList.add('valid-inventory-target');
        });
      }
    },
    onDragEnd(e: MouseEvent) {
      if (!this.draggingItem) return;

      this.removeClothingSlotListeners();
      this.removeInventorySlotListeners();

      if (e.target instanceof HTMLElement && 
          (e.target.closest('.split-overlay') || document.querySelector('.split-overlay'))) {
        return;
      }
      
      if (this.draggingFromClothing && this.draggingClothingIndex >= 0) {
        if (e.target instanceof HTMLElement) {
          const target = e.target.closest(".ct-box-item-inventory-pets") as HTMLElement | null;
          
          if (target && (target as HTMLElement).dataset.slot) {
            const toSlot = parseInt((target as HTMLElement).dataset.slot || "0");
            this.unequipClothingItem(this.draggingClothingIndex, toSlot);
          }
        }
        
        this.cleanupDrag();
        return;
      }
      
      if (!(e.target instanceof HTMLElement)) {
        this.cleanupDrag();
        return;
      }
      
      const clothingSlotTarget = e.target.closest(".clothing-slot") as HTMLElement | null;
      if (clothingSlotTarget && this.draggingItem.dataset.slot) {
        const clothingContainer = clothingSlotTarget.closest(".ct-clothing-slot-container") as HTMLElement | null;
        if (clothingContainer) {
          const slotIndex = (clothingContainer as HTMLElement).dataset.slotIndex?.replace('clothing-', '') || "";
          const originSlot = +this.draggingItem.dataset.slot;
          const originItem = this.inventoryItemsMenu[originSlot];
          
          if (slotIndex && originItem) {
            const targetClothingIndex = parseInt(slotIndex);
            this.equipItemToClothingSlot(originItem, originSlot, targetClothingIndex);
            this.cleanupDrag();
            return;
          }
        }
      }

      if (!this.draggingItem.dataset.slot) {
        this.cleanupDrag();
        return;
      }

      const originSlot = +this.draggingItem.dataset.slot;
      const originItem = this.inventoryItemsMenu[originSlot];
      const target = e.target.closest(".ct-box-item-inventory-pets") as HTMLElement | null;
        
      if (target && (target as HTMLElement).dataset.slot) {
        const toSlot = parseInt((target as HTMLElement).dataset.slot || "0");

        if (toSlot !== originSlot) {
          const toItem = this.inventoryItemsMenu[toSlot];
          
          if (this.isShiftDragging && this.splitSourceSlot === originSlot) {
            if (!toItem) {
              this.showSplitInterface(toSlot);
              return;
            }
          } 
          else {
            const originItemSpec = this.getSpec(originItem);
            
            if (toItem) {
              if (toItem.item === originItem.item && originItemSpec.stack) {
                toItem.quantity += originItem.quantity;
                delete this.inventoryItemsMenu[originSlot];
              } else {
                this.inventoryItemsMenu[originSlot] = toItem;
                this.inventoryItemsMenu[toSlot] = originItem;
              }
            } else {
              delete this.inventoryItemsMenu[originSlot];
              this.inventoryItemsMenu[toSlot] = originItem;
            }
              
              this.postNUI("inv-move-item", { fromSlot: originSlot, toSlot });
          }
        }
      }

      this.$forceUpdate();
      
      if (!document.querySelector('.split-overlay')) {
        this.cleanupDrag();
      }
    },
    handleNUI({ action, data }: { action: string; data: unknown }) {
      switch(action) {
        case "setPos": {
          const props = data as { left: number; top: number };
          this.left = props.left;
          this.top = props.top;
          break;
        }
          
        case "setMenus": {
          this.menus = (data as { menus: IPetsMenu[] }).menus;
          this.menus.forEach(menu => menu.hover = false);
          break;
        }
          
        case "setMode": {
          this.mode = (data as { mode: number }).mode;
          this.menus.forEach(menu => menu.hover = false);
          break;
        }
          
        case "setScale": {
          this.scale = (data as { scale: number }).scale;
          break;
        }
          
        case "highlight": {
          const name = (data as { name: string }).name;
          this.menus.forEach((item) => {
            if (item.name === name) {
              item.hover = true;
              setTimeout(() => { item.hover = false; }, 250);
            }
          });
          break;
        }
          
        case "updateInventory": {
          this.inventoryItemsMenu = this.processInventoryItems(
            (data as { view: { [slot: number]: IInventoryPetsMenuItem } }).view
          );
          
          this.cleanupDrag();
          this.placeHolderItem = null;
          this.inventoryMenu.forEach(item => item.hover = false);
          
          this.processingUnequip.clear();
          this.processingEquip.clear();
          break;
        }
          
        case "update-item-specs": {
          const specs = data as { specs: { [item: string]: IInventoryItemSpec }; slots: number };
          this.inventoryItemSpecs = specs.specs;
          this.maxInventorySlot = specs.slots;
          
          this.inventoryItemsMenu = this.processInventoryItems(this.inventoryItemsMenu);
          break;
        }
          
        case "updateStats": {
          this.petProgress = (data as { stats: { [name: string]: number } }).stats;
          break;
        }
          
        case "updateStatsBars": {
          this.statsPet = (data as { bars: IPetBars[] }).bars;
          break;
        }
          
        case "updatePetClothing": {
          const clothingData = data as { 
            clothing: { [type: string]: IInventoryPetsMenuItem | null },
            attachProps: { [type: string]: IInventoryPetsMenuItem | null },
            petType: string 
          };
          
          this.currentPetType = clothingData.petType || 'default';
          
          for (const slot of this.clothingSlots) {
            if (slot.attach) {
              slot.item = clothingData.attachProps?.[slot.type] || null;
            } else {
              slot.item = clothingData.clothing[slot.type] || null;
            }
          }
          
          this.processingUnequip.clear();
          this.processingEquip.clear();
          break;
        }
          
        case "pet-equip-response": {
          const response = data as {
            success: boolean;
            message?: string; 
            clothing?: { [type: string]: IInventoryPetsMenuItem | null };
            inventory?: { [slot: number]: IInventoryPetsMenuItem };
          };
          
          if (response.clothing) {
            for (const slot of this.clothingSlots) {
              slot.item = response.clothing[slot.type] || null;
            }
          }
          
          if (response.inventory) {
            this.inventoryItemsMenu = this.processInventoryItems(response.inventory);
          }
          
          this.processingEquip.clear();
          this.processingUnequip.clear();
          break;
        }
      }
    },
    onKeyUp(e: KeyboardEvent) {
      if (!this.visible) return;

      if (e.key === "Escape") {
        if (this.mode === 0) {
          this.postNUI("escape", {});
        }
        else if (this.mode === 2 || this.mode === 3) {
          this.cleanupDrag();
          this.placeHolderItem = null;
          this.mode = 0;
        }
        return;
      }
      
      if (this.mode === 2 && e.key === "Delete" && this.placeHolderItem) {
            const spec = this.getSpec(this.placeHolderItem);
            if (spec.canbeRemoved) {
              this.postNUI("inv-del-item", this.placeHolderItem);
        }
      }
    },
    onClickMenu(item: IPetsMenu) {
      this.postNUI("menu-choose", { event: item.event, args: item.args });
    },
    /** Imagens vêm do recurso cdev_pets para funcionar com pet shop/inventário. */
    getIcon(item: string) {
      return item ? `nui://cdev_pets/html/pets/inventory/${item}.webp` : '';
    },
    onPetImageError(e: Event) {
      const el = e.target as HTMLImageElement;
      if (!el || (el as any).__petsPlaceholder) return;
      (el as any).__petsPlaceholder = true;
      el.onerror = null;
      el.src = 'nui://cdev_pets/html/pets/inventory/placeholder.webp';
    },
    getSpec(item: IInventoryPetsMenuItem) {
      return this.inventoryItemSpecs[item.item];
    },
    showSplitInterface(targetSlot: number) {
      if (!this.splitSourceSlot) return;
      
      const sourceItem = this.inventoryItemsMenu[this.splitSourceSlot];
      const maxAmount = sourceItem.quantity - 1;
      
      const overlay = document.createElement('div');
      overlay.className = 'split-overlay';
      overlay.style.position = 'fixed';
      overlay.style.zIndex = '9999';
      
      const container = document.createElement('div');
      container.className = 'split-container';
      
      const title = document.createElement('div');
      title.className = 'split-title';
      title.innerHTML = `${this.locale("split_item")} <span class="keyboard-hint">[SHIFT]</span>`;
      
      const amountSelector = document.createElement('div');
      amountSelector.className = 'split-amount-selector';
      
      const slider = document.createElement('input');
      slider.type = 'range';
      slider.min = '1';
      slider.max = maxAmount.toString();
      slider.value = '1';
      slider.className = 'split-slider';
      
      const amountDisplay = document.createElement('div');
      amountDisplay.className = 'split-amount-display';
      amountDisplay.textContent = '1';
      
      const buttonsContainer = document.createElement('div');
      buttonsContainer.className = 'split-buttons-container';
      
      const confirmButton = document.createElement('button');
      confirmButton.className = 'split-button confirm';
      confirmButton.textContent = this.locale("confirm");
      
      const cancelButton = document.createElement('button');
      cancelButton.className = 'split-button cancel';
      cancelButton.textContent = this.locale("cancel");
      
      slider.addEventListener('input', () => {
        this.splitAmount = parseInt(slider.value);
        amountDisplay.textContent = slider.value;
      });
      
      confirmButton.addEventListener('click', (e) => {
        e.stopPropagation();
        this.performSplit(this.splitSourceSlot as number, targetSlot, this.splitAmount);
        document.body.removeChild(overlay);
      });
      
      cancelButton.addEventListener('click', (e) => {
        e.stopPropagation();
        document.body.removeChild(overlay);
        this.cleanupDrag();
      });
      
      overlay.addEventListener('mousedown', e => e.stopPropagation());
      overlay.addEventListener('mouseup', e => e.stopPropagation());
      overlay.addEventListener('click', e => e.stopPropagation());
      
      amountSelector.appendChild(slider);
      amountSelector.appendChild(amountDisplay);
      
      buttonsContainer.appendChild(confirmButton);
      buttonsContainer.appendChild(cancelButton);
      
      container.appendChild(title);
      container.appendChild(amountSelector);
      container.appendChild(buttonsContainer);
      
      overlay.appendChild(container);
      document.body.appendChild(overlay);
    },
    performSplit(fromSlot: number, toSlot: number, amount: number) {
      const sourceItem = this.inventoryItemsMenu[fromSlot];
      if (!sourceItem || sourceItem.quantity <= amount) return;
      
      this.inventoryItemsMenu[toSlot] = { 
        ...sourceItem, 
        quantity: amount 
      };
      
      sourceItem.quantity -= amount;
      
      this.postNUI("inv-split-item", { 
        fromSlot, 
        toSlot, 
        quantity: amount 
      });
      
      this.cleanupDrag();
      this.$forceUpdate();
    },
    onMouseEnterClothing(e: MouseEvent, slotIndex: number) {
      const slot = this.clothingSlots[slotIndex];
      if (slot.item) {
        this.placeHolderItem = slot.item;
        this.placeHolderClothingItem = { item: slot.item, slotIndex };
      } else {
        this.placeHolderItem = null;
        this.placeHolderClothingItem = null;
      }
    },
    onMouseLeaveClothing(slotIndex: number) {
      this.placeHolderItem = null;
      this.placeHolderClothingItem = null;
    },
    onDragStartClothing(e: MouseEvent, slotIndex: number) {
      if (e.button === 2) {
        const slot = this.clothingSlots[slotIndex];
        if (slot.item) {
          const currentTime = Date.now();
          const DEBOUNCE_DELAY = 500;
          
          if (this.processingUnequip.has(slotIndex)) {
            return;
          }
          
          if (this.lastUnequipTime[slotIndex] && 
              (currentTime - this.lastUnequipTime[slotIndex]) < DEBOUNCE_DELAY) {
            return;
          }
          
          let targetInventorySlot = -1;
          
          for (let i = 1; i <= this.maxInventorySlot; i++) {
            if (!this.inventoryItemsMenu[i]) {
              targetInventorySlot = i;
              break;
            }
          }
          
          if (targetInventorySlot !== -1) {
            this.processingUnequip.add(slotIndex);
            this.lastUnequipTime[slotIndex] = currentTime;
            
            this.unequipClothingItem(slotIndex, targetInventorySlot);
            this.showFloatingMessage(this.locale('item_unequipped'), targetInventorySlot);
            
            setTimeout(() => {
              this.processingUnequip.delete(slotIndex);
            }, DEBOUNCE_DELAY);
          }
        }
        return;
      }
      
      if (e.button !== 0) return;
      
      const slot = this.clothingSlots[slotIndex];
      if (!slot.item) return;
      
      const clothingSlotElement = (e.target as HTMLElement)?.closest('.clothing-slot') as HTMLElement;
      if (!clothingSlotElement) return;
      
      if (this.draggingItem) {
        this.draggingItem.remove();
        this.draggingItem = null;
      }
      
      const clone = clothingSlotElement.cloneNode(true) as HTMLElement;
      clone.style.position = 'absolute';
      clone.style.pointerEvents = 'none';
      clone.style.zIndex = '1000';
      
      const rect = clothingSlotElement.getBoundingClientRect();
      clone.style.width = rect.width + 'px';
      clone.style.height = rect.height + 'px';
      clone.dataset.clothingIndex = slotIndex.toString();
      
      document.body.appendChild(clone);
      
      clone.style.left = (e.clientX - rect.width / 2) + 'px';
      clone.style.top = (e.clientY - rect.height / 2) + 'px';
      clone.style.visibility = 'visible';
      
      this.draggingItem = clone;
      this.draggingFromClothing = true;
      this.draggingClothingIndex = slotIndex;
    },
    isItemValidForClothingSlot(item: IInventoryPetsMenuItem, slotIndex: number): boolean {
      const slot = this.clothingSlots[slotIndex];
      if (slot.attach) {
        if (!item.attachData) return false;
        return item.attachData.slot === slot.type;
      } else {
        if (!item.clothingData) return false;
        return item.clothingData.slot === slot.type;
      }
    },
    equipItemToClothingSlot(item: IInventoryPetsMenuItem, sourceSlot: number, targetSlotIndex: number) {
      if (!this.isItemValidForClothingSlot(item, targetSlotIndex)) return;
      
      const currentTime = Date.now();
      const DEBOUNCE_DELAY = 500; 
      const equipKey = `${sourceSlot}-${targetSlotIndex}`;
      
      if (this.processingEquip.has(equipKey)) {
        return;
      }
      
      if (this.lastEquipTime[equipKey] && 
          (currentTime - this.lastEquipTime[equipKey]) < DEBOUNCE_DELAY) {
        return;
      }
      
      this.processingEquip.add(equipKey);
      this.lastEquipTime[equipKey] = currentTime;
      
      const targetSlot = this.clothingSlots[targetSlotIndex];
      if (targetSlot.item) {
        let emptySlot = -1;
        for (let i = 1; i <= this.maxInventorySlot; i++) {
          if (!this.inventoryItemsMenu[i]) {
            emptySlot = i;
            break;
          }
        }
        
        if (emptySlot === -1) {
          this.showFloatingMessage(this.locale('no_empty_slots'), sourceSlot);
          this.processingEquip.delete(equipKey);
          return;
        }
        
        if (targetSlot.attach) {
          this.postNUI("pet-unequip-attach", {
            attachType: targetSlot.type,
            item: targetSlot.item.item,
            toSlot: emptySlot,
            thenEquip: {
              fromSlot: sourceSlot,
              attachType: this.clothingSlots[targetSlotIndex].type,
              item: item.item
            }
          });
        } else {
          this.postNUI("pet-unequip-clothing", {
            clothingType: targetSlot.type,
            item: targetSlot.item.item,
            toSlot: emptySlot,
            thenEquip: {
              fromSlot: sourceSlot,
              clothingType: this.clothingSlots[targetSlotIndex].type,
              item: item.item
            }
          });
        }
      } else {
        if (targetSlot.attach) {
          this.postNUI("pet-equip-attach", {
            fromSlot: sourceSlot,
            attachType: this.clothingSlots[targetSlotIndex].type,
            item: item.item
          });
        } else {
          this.postNUI("pet-equip-clothing", {
            fromSlot: sourceSlot,
            clothingType: this.clothingSlots[targetSlotIndex].type,
            item: item.item
          });
        }
      }
      
      setTimeout(() => {
        this.processingEquip.delete(equipKey);
      }, DEBOUNCE_DELAY);
    },
    unequipClothingItem(clothingIndex: number, targetInventorySlot: number) {
      const sourceSlot = this.clothingSlots[clothingIndex];
      if (!sourceSlot.item) return;
      
      if (sourceSlot.attach) {
        this.postNUI("pet-unequip-attach", {
          attachType: sourceSlot.type,
          item: sourceSlot.item.item,
          toSlot: targetInventorySlot
        });
      } else {
        this.postNUI("pet-unequip-clothing", {
          clothingType: sourceSlot.type,
          item: sourceSlot.item.item,
          toSlot: targetInventorySlot
        });
      }
    },
    addClothingSlotListeners(sourceSlot: number) {
      const sourceItem = this.inventoryItemsMenu[sourceSlot];
      if (!sourceItem || (!sourceItem.clothingData && !sourceItem.attachData)) return;
      
      const clothingSlots = document.querySelectorAll('.clothing-slot');
      
      clothingSlots.forEach((slotEl) => {
        const container = slotEl.closest('.ct-clothing-slot-container') as HTMLElement | null;
        if (!container) return;
        
        const slotType = (container as HTMLElement).dataset.clothingType || "";
        
        const itemSlotType = sourceItem.clothingData?.slot || sourceItem.attachData?.slot;
        
        if (itemSlotType === slotType) {
          slotEl.classList.add('valid-target');
        } else {
          slotEl.classList.add('invalid-target');
        }
      });
    },
    removeClothingSlotListeners() {
      document.querySelectorAll('.valid-target, .invalid-target').forEach(el => {
        el.classList.remove('valid-target', 'invalid-target');
      });
    },
    removeInventorySlotListeners() {
      document.querySelectorAll('.valid-inventory-target').forEach(el => {
        el.classList.remove('valid-inventory-target');
      });
    },
    useItem(item: IInventoryPetsMenuItem) {
      const spec = this.getSpec(item);
      if (!spec.usable || !spec.onUse) return;
      
      this.postNUI("inv-use-item", {
        event: spec.onUse.event,
        net: spec.onUse.net,
        close: spec.onUse.close,
        preventRestoreState: spec.onUse.preventRestoreState,
        item: item.item,
        isPremiumPackage: spec.isPremiumPackage,
        data: {
          ...(spec.onUse.data || {}),
          metadata: item.metadata,
        },
      });
    },
    deleteItem(item: IInventoryPetsMenuItem) {
      if (!this.getSpec(item)?.canbeRemoved) return;
      this.postNUI("inv-del-item", item);
    },
    initiateItemSplit(item: IInventoryPetsMenuItem) {
      if (item.quantity <= 1) return;
      
      this.isShiftDragging = true;
    },
    processInventoryItems(items: { [slot: number]: IInventoryPetsMenuItem }) {
      const processedItems = {...items};
      
      Object.entries(processedItems).forEach(([slotKey, item]) => {
        const spec = this.inventoryItemSpecs[item.item];
        
        if (spec?.clothingData && !item.clothingData) {
          item.clothingData = {
            slot: spec.clothingData.slot,
            petType: spec.clothingData.petType,
            properties: spec.clothingData.properties
          };
        }
        
        if (spec?.attachData && !item.attachData) {
          item.attachData = {
            slot: spec.attachData.slot,
            petType: spec.attachData.petType,
            attachInfo: spec.attachData.attachInfo,
            properties: spec.attachData.properties
          };
        }
      });
      
      return processedItems;
    },
    quickEquipItem(item: IInventoryPetsMenuItem) {
      let targetType: string | undefined;
      let isAttach = false;
      
      if (item.clothingData) {
        targetType = item.clothingData.slot;
        isAttach = false;
      } else if (item.attachData) {
        targetType = item.attachData.slot;
        isAttach = true;
      }
      
      if (!targetType) return;
      
      const targetSlotIndex = this.clothingSlots.findIndex(slot => 
        slot.type === targetType && (isAttach ? slot.attach : !slot.attach)
      );
      
      if (targetSlotIndex !== -1) {
        this.equipItemToClothingSlot(item, item.slot || 0, targetSlotIndex);
      }
    },
    quickUnequipItem(slotIndex: number) {
      const currentTime = Date.now();
      const DEBOUNCE_DELAY = 500; 
      
      if (this.processingUnequip.has(slotIndex)) {
        return;
      }
      
      if (this.lastUnequipTime[slotIndex] && 
          (currentTime - this.lastUnequipTime[slotIndex]) < DEBOUNCE_DELAY) {
        return;
      }
      
      for (let i = 1; i <= this.maxInventorySlot; i++) {
        if (!this.inventoryItemsMenu[i]) {
          this.processingUnequip.add(slotIndex);
          this.lastUnequipTime[slotIndex] = currentTime;
          
          this.unequipClothingItem(slotIndex, i);
          
          setTimeout(() => {
            this.processingUnequip.delete(slotIndex);
          }, DEBOUNCE_DELAY);
          break;
        }
      }
    },
    showFloatingMessage(message: string, slotIndex: number) {
      const slotElement = document.querySelector(`[data-slot="${slotIndex}"]`) as HTMLElement;
      if (!slotElement) return;
      
      const messageEl = document.createElement('div');
      messageEl.className = 'floating-message';
      messageEl.textContent = message;
      
      const rect = slotElement.getBoundingClientRect();
      messageEl.style.left = `${rect.left + rect.width/2}px`;
      messageEl.style.top = `${rect.top}px`;
      
      document.body.appendChild(messageEl);
      
      setTimeout(() => {
        messageEl.classList.add('floating');
        setTimeout(() => {
          messageEl.remove();
        }, 1000);
      }, 10);
    },
    cleanupDrag() {
      if (this.draggingItem) {
        this.draggingItem.remove();
        this.draggingItem = null;
      }
      this.isShiftDragging = false;
      this.splitSourceSlot = null;
      this.draggingFromClothing = false;
      this.draggingClothingIndex = -1;
      
      this.processingUnequip.clear();
      this.processingEquip.clear();
    },
  },
  mounted() {
    window.addEventListener("keyup", this.onKeyUp);
    window.addEventListener("mouseup", this.onDragEnd);
  },
  beforeUnmount() {
    window.removeEventListener("keyup", this.onKeyUp);
    window.removeEventListener("mouseup", this.onDragEnd);

  },
});
</script>

