<script lang="ts">
import { defineComponent } from "vue";
import NuiComponentMixin from "@/mixins/NuiComponentMixin";
import { ShopFake } from "@/fakebackend/shopFake";
import { IMenuShop } from "@/interfaces/IMenuShop";
import paginationComponentVue from "@/utils/paginationComponent.vue";
import { ISubMenuShop } from "@/interfaces/ISubMenuShop";
import { IShop } from "@/interfaces/IShop";
import { IItemShop } from "@/interfaces/IItemsShop";

const jsonClone = <T extends object | undefined>(obj: T): T => obj === undefined ? undefined : JSON.parse(JSON.stringify(obj));

const emptySubMenu: ISubMenuShop = { name: "", items: [] };
const getFirstSubMenu = (menu: IMenuShop | undefined): ISubMenuShop =>
  menu?.subMenu?.length ? menu.subMenu[0] : emptySubMenu;

export default defineComponent({
  name: "cDevShop",
  components: {
    paginationComponentVue,
  },
  mixins: [NuiComponentMixin],
  data() {
    return {
      shop: ShopFake,
      selectedMenu: {} as IMenuShop | undefined,
      selectedSubMenu: {} as ISubMenuShop | undefined,
      searchSubMenu: {} as ISubMenuShop | undefined,
      currentPage: 0,
      screenWidth: 0,
      balance: 0,
      customCurrencyBalance: 0,
      customCurrencyLabel: "",
      customCurrencyIcon: "",
      logo: "https://static.cdev.shop/resources/vehicle-shop/thumbnails/cdev.png",
      searchQuery: "",
    };
  },
  computed: {
    safeMaxPage(): number {
      const len = this.searchSubMenu?.items?.length ?? 0;
      const perPage = this.MaxItemsOnPage?.() ?? 10;
      const max = Math.ceil(len / perPage);
      return Number.isFinite(max) && max >= 0 ? max : 0;
    },
    safeShopItems(): IItemShop[] {
      const items = this.searchSubMenu?.items ?? [];
      const start = (this.currentPage || 0) * (this.MaxItemsOnPage?.() ?? 10);
      const end = start + (this.MaxItemsOnPage?.() ?? 10);
      return items.slice(start, end).filter((x): x is IItemShop => x != null && typeof x === "object");
    },
  },
  props: {
    name: {
      type: String,
    },
    visible: {
      type: Boolean,
    },
    locale: {
      type: Function,
      required: true,
    },
  },
  methods: {
    formatMoney(value: unknown): string {
      const num = value != null && value !== "" ? Number(value) : 0;
      const safe = Number.isFinite(num) ? num : 0;
      return String(safe).replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    },
    MaxItemsOnPage() {
      /*if (this.screenWidth <= 1280) {
        return 6;
      } else if (this.screenWidth <= 1366) {
        return 10;
      } else if (this.screenWidth <= 1440) {
        return 8;
      } else if (this.screenWidth <= 1536) {
        return 10;
      } else if (this.screenWidth <= 1600) {
        return 8;
      } else if (this.screenWidth <= 1680) {
        return 8;
      } else if (this.screenWidth <= 1792) {
        return 8;
      } else if (this.screenWidth <= 1920) {
        return 10;
      } else if (this.screenWidth <= 2560) {
        return 10;
      }*/

      return 10;
    },
    handleNUI({ action, data }: { action: string; data: unknown }) {
      if (action === "setShop") {
        const { shop } = data as { shop: IShop };

        this.shop = shop ?? this.shop;
        this.customCurrencyBalance = 0;
        this.customCurrencyLabel = "";
        this.customCurrencyIcon = "";
        const firstMenu = this.shop?.mainMenu?.length ? this.shop.mainMenu[0] : undefined;
        this.selectedMenu = firstMenu;
        const firstSub = getFirstSubMenu(firstMenu);
        this.selectedSubMenu = firstSub;
        this.searchSubMenu = jsonClone(firstSub) ?? emptySubMenu;
        this.currentPage = 0;
      } else if (action == "setBalance") {
        const { balance } = data as { balance?: number };

        this.balance = balance != null && Number.isFinite(Number(balance)) ? Number(balance) : 0;
      } else if (action === "setCustomCurrencyBalance") {
        const { balance, currencyKey, currencyLabel } = data as {
          balance?: number | null;
          currencyKey?: string | null;
          currencyLabel?: string | null;
        };
        if (balance == null && currencyLabel == null) {
          this.customCurrencyBalance = 0;
          this.customCurrencyLabel = "";
        } else {
          this.customCurrencyBalance =
            balance != null && Number.isFinite(Number(balance)) ? Number(balance) : 0;
          this.customCurrencyLabel =
            typeof currencyLabel === "string" && currencyLabel
              ? currencyLabel
              : typeof currencyKey === "string" && currencyKey
                ? currencyKey
                : "";
        }
      } else if (action === "setCustomCurrencyIcon") {
        const { iconUrl } = data as { iconUrl?: string | null };
        this.customCurrencyIcon = typeof iconUrl === "string" && iconUrl !== "" ? iconUrl : "";
      } else if (action == "setLogo") {
        const { logo } = data as { logo: string };

        this.logo = logo;
      }
    },
    handleKeyDown(e: KeyboardEvent) {
      if (!this.visible) return;

      if (e.key === "Escape") {
        this.postNUI("close", {});
      }
    },
    setSelectedMenu(menu: IMenuShop) {
      this.selectedMenu = menu;
      const firstSub = getFirstSubMenu(menu);
      this.selectedSubMenu = firstSub;
      this.searchSubMenu = jsonClone(firstSub) ?? emptySubMenu;
      this.currentPage = 0;
    },
    setSelectedSubMenu(subMenu: ISubMenuShop) {
      this.selectedSubMenu = subMenu;
      this.searchSubMenu = jsonClone(subMenu);
      this.currentPage = 0;
    },
    buyItem(button: string, item: IItemShop) {
      this.postNUI("buyItem", { button, item });
    },
    addCountItem(item: IItemShop) {
      if (item.lockQuantity) return;

      item.quantity = Math.min(
        (item.quantity || 0) + 1,
        item.maxQuantity || Infinity
      );
      //this.postNUI("updateItemCount", { item });
    },
    decreaseCountItem(item: IItemShop) {
      if (item.lockQuantity) return;

      item.quantity = Math.max((item.quantity || 0) - 1, item.minQuantity || 0);
      //this.postNUI("updateItemCount", { item });
    },
    handleChangePage(page: number) {
      const max = this.safeMaxPage;
      this.currentPage = Math.max(0, Math.min(page - 1, max - 1));
    },
    getScreenSize() {
      this.screenWidth = window.innerWidth;
    },
    handleSearch() {
      if (this.searchSubMenu && this.selectedSubMenu) {
        const filteredItems = this.selectedSubMenu.items.filter((item) => {
          return item.name.trim().toLowerCase().includes(this.searchQuery.trim().toLowerCase()) || this.searchQuery.trim() === "";
        });
        // Sempre copiar o array para não partilhar referência com selectedSubMenu.items (evita travamentos ao mudar de página/categoria)
        this.searchSubMenu.items = filteredItems.slice();
      }
    },
    onShopImageError(e: Event) {
      const el = (e.target as HTMLImageElement);
      if (!el || (el as any).__shopPlaceholder) return;
      (el as any).__shopPlaceholder = true;
      el.onerror = null;
      el.src = "nui://cdev_pets/html/pets/inventory/placeholder.webp";
    },
  },
  mounted: function () {
    window.addEventListener("keydown", this.handleKeyDown);
    window.addEventListener("resize", this.getScreenSize);
  },
  unmounted: function () {
    window.removeEventListener("keydown", this.handleKeyDown);
    window.removeEventListener("resize", this.getScreenSize);
  },
  created: function () {
    const firstMenu = this.shop?.mainMenu?.length ? this.shop.mainMenu[0] : undefined;
    this.selectedMenu = firstMenu;
    const firstSub = getFirstSubMenu(firstMenu);
    this.selectedSubMenu = firstSub;
    this.searchSubMenu = jsonClone(firstSub) ?? emptySubMenu;
    this.getScreenSize();
  },
});
</script>
